INSERT INTO incidents (id, status_page_id, endpoint_id, title, description, status, impact, started_at, resolved_at, created_at, updated_at) VALUES
  (1, 1, 3, 'Elevated latency in Public API', 'We are investigating elevated response times affecting a subset of API requests.', 'investigating', 'minor', NOW() - INTERVAL '70 minutes', NULL, NOW() - INTERVAL '70 minutes', NOW() - INTERVAL '15 minutes'),
  (2, 2, 9, 'Checkout errors affecting some payments', 'Some customers may see intermittent 502 errors during checkout redirects.', 'identified', 'major', NOW() - INTERVAL '25 minutes', NULL, NOW() - INTERVAL '25 minutes', NOW() - INTERVAL '5 minutes'),
  (3, 3, 13, 'Auth API unavailable', 'Authentication requests are failing due to DNS and connection errors on the auth service.', 'monitoring', 'critical', NOW() - INTERVAL '40 minutes', NULL, NOW() - INTERVAL '40 minutes', NOW() - INTERVAL '2 minutes'),
  (4, 1, 4, 'Webhook delivery delays', 'Outbound webhook deliveries were delayed after a queue backlog increase.', 'resolved', 'minor', NOW() - INTERVAL '1 day 6 hours', NOW() - INTERVAL '1 day 4 hours', NOW() - INTERVAL '1 day 6 hours', NOW() - INTERVAL '1 day 4 hours'),
  (5, 2, NULL, 'Planned database maintenance completed', 'Scheduled database maintenance completed successfully with minimal impact.', 'resolved', 'none', NOW() - INTERVAL '3 days', NOW() - INTERVAL '3 days' + INTERVAL '90 minutes', NOW() - INTERVAL '3 days', NOW() - INTERVAL '3 days' + INTERVAL '90 minutes');
INSERT INTO incident_updates (id, incident_id, status, message, author_label, published_at, created_at) VALUES
  (1, 1, 'investigating', 'We are investigating elevated latency on the Public API. Initial symptoms began impacting a portion of requests.', 'StatusPe', NOW() - INTERVAL '70 minutes', NOW() - INTERVAL '70 minutes'),
  (2, 1, 'identified', 'We identified slow queries on a shared database cluster and are applying mitigations.', 'StatusPe', NOW() - INTERVAL '25 minutes', NOW() - INTERVAL '25 minutes'),
  (3, 2, 'investigating', 'We are investigating intermittent checkout failures affecting redirect flows for some users in Peru.', 'StatusPe', NOW() - INTERVAL '25 minutes', NOW() - INTERVAL '25 minutes'),
  (4, 2, 'identified', 'The issue has been identified as an upstream gateway problem. We are routing traffic away from the affected nodes.', 'StatusPe', NOW() - INTERVAL '5 minutes', NOW() - INTERVAL '5 minutes'),
  (5, 3, 'investigating', 'We are investigating an outage impacting the Auth API.', 'StatusPe', NOW() - INTERVAL '40 minutes', NOW() - INTERVAL '40 minutes'),
  (6, 3, 'identified', 'We identified DNS resolution instability in the auth service path and are applying corrective changes.', 'StatusPe', NOW() - INTERVAL '18 minutes', NOW() - INTERVAL '18 minutes'),
  (7, 3, 'monitoring', 'A fix has been deployed and we are monitoring recovery. Some requests may still fail while caches refresh.', 'StatusPe', NOW() - INTERVAL '2 minutes', NOW() - INTERVAL '2 minutes'),
  (8, 4, 'investigating', 'Webhook deliveries are delayed for some customers.', 'StatusPe', NOW() - INTERVAL '1 day 6 hours', NOW() - INTERVAL '1 day 6 hours'),
  (9, 4, 'monitoring', 'Queue backlog has cleared and webhook throughput is returning to normal.', 'StatusPe', NOW() - INTERVAL '1 day 4 hours 30 minutes', NOW() - INTERVAL '1 day 4 hours 30 minutes'),
  (10, 4, 'resolved', 'This incident has been resolved.', 'StatusPe', NOW() - INTERVAL '1 day 4 hours', NOW() - INTERVAL '1 day 4 hours'),
  (11, 5, 'resolved', 'The planned maintenance was completed successfully.', 'StatusPe', NOW() - INTERVAL '3 days' + INTERVAL '90 minutes', NOW() - INTERVAL '3 days' + INTERVAL '90 minutes');
